## GC for Snapshots

Old snapshots should be cleaned up periodically:

```typescript
function pruneSnapshots(
  snapshots: WorkingCopySnapshot,
  olderThanDays: number = 7
): number {
  const threshold = Date.now() - (olderThanDays * 24 * 60 * 60 * 1000);

  const result = this.db.prepare(`
    DELETE FROM wc_snapshots WHERE created_at < ?
  `).run(threshold);

  return result.changes;
}
```

# Error Handling and Recovery

Parent: [[s-9brh|Multi-Agent Git Tracking System]]

## Error Classes

```typescript
/**
 * Base class for git operation failures.
 */
class GitOperationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'GitOperationError';
  }
}

/**
 * Merge/rebase conflict occurred.
 */
class ConflictError extends GitOperationError {
  conflictedFiles: string[];
  operation: 'rebase' | 'merge' | 'cherry_pick';

  constructor(
    conflictedFiles: string[],
    operation: 'rebase' | 'merge' | 'cherry_pick'
  ) {
    super(`Conflict in ${operation}: ${conflictedFiles.join(', ')}`);
    this.name = 'ConflictError';
    this.conflictedFiles = conflictedFiles;
    this.operation = operation;
  }
}

/**
 * Referenced branch does not exist.
 */
class BranchNotFoundError extends GitOperationError {
  branch: string;

  constructor(branch: string) {
    super(`Branch not found: ${branch}`);
    this.name = 'BranchNotFoundError';
    this.branch = branch;
  }
}

/**
 * Worktree operation failed.
 */
class WorktreeError extends GitOperationError {
  worktree: string;

  constructor(message: string, worktree: string) {
    super(message);
    this.name = 'WorktreeError';
    this.worktree = worktree;
  }
}

/**
 * Stream not found in database.
 */
class StreamNotFoundError extends Error {
  streamId: string;

  constructor(streamId: string) {
    super(`Stream not found: ${streamId}`);
    this.name = 'StreamNotFoundError';
    this.streamId = streamId;
  }
}

/**
 * Stream has unresolved conflicts that block an operation.
 */
class UnresolvedConflictsError extends Error {
  conflicts: ConflictRecord[];

  constructor(message: string, conflicts: ConflictRecord[]) {
    super(message);
    this.name = 'UnresolvedConflictsError';
    this.conflicts = conflicts;
  }
}

/**
 * Dependency graph has cycles.
 */
class CyclicDependencyError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'CyclicDependencyError';
  }
}

/**
 * Database and git state are out of sync.
 */
class DesyncError extends Error {
  streamId: string;
  dbState: string;
  gitState: string;

  constructor(streamId: string, dbState: string, gitState: string) {
    super(`Stream ${streamId} desync: DB=${dbState}, Git=${gitState}`);
    this.name = 'DesyncError';
    this.streamId = streamId;
    this.dbState = dbState;
    this.gitState = gitState;
  }
}

/**
 * Operation failed mid-way and may need recovery.
 */
class PartialOperationError extends Error {
  operationId: string;
  completedSteps: string[];
  failedStep: string;

  constructor(
    operationId: string,
    completedSteps: string[],
    failedStep: string,
    cause: Error
  ) {
    super(`Partial operation ${operationId}: failed at ${failedStep}`);
    this.name = 'PartialOperationError';
    this.operationId = operationId;
    this.completedSteps = completedSteps;
    this.failedStep = failedStep;
    this.cause = cause;
  }
}
```

## Recovery Strategies

| Failure | Detection | Recovery |
|---------|-----------|----------|
| Rebase conflict | Non-zero exit + conflict markers | Abort rebase, report conflicts, let agent/human resolve |
| Merge conflict | Non-zero exit + conflict markers | Abort merge, report conflicts |
| Corrupted worktree | Git status fails | Delete and recreate worktree |
| DB/Git desync | Stream in DB but not git | Recreate branch from recorded base, or mark stream as broken |
| Crashed mid-operation | Operation started but not completed | On restart, check for uncommitted state, rollback or complete |

## Recovery Implementations

### Conflict Recovery

```typescript
function recoverFromConflict(
  worktree: string,
  operation: 'rebase' | 'merge'
): void {
  if (operation === 'rebase') {
    execSync('git rebase --abort', { cwd: worktree });
  } else {
    execSync('git merge --abort', { cwd: worktree });
  }
}
```

### Worktree Recovery

```typescript
function recoverWorktree(
  repoPath: string,
  worktreePath: string,
  agentId: string
): void {
  // Remove corrupted worktree
  try {
    execSync(`git worktree remove --force ${worktreePath}`, { cwd: repoPath });
  } catch {
    // Worktree might already be gone
  }

  // Clean up filesystem if needed
  if (fs.existsSync(worktreePath)) {
    fs.rmSync(worktreePath, { recursive: true });
  }

  // Recreate
  execSync(`git worktree add ${worktreePath} main`, { cwd: repoPath });

  // Update database
  db.prepare(`
    UPDATE agent_worktrees
    SET current_stream = NULL, last_active = ?
    WHERE agent_id = ?
  `).run(Date.now(), agentId);
}
```

### DB/Git Desync Recovery

```typescript
interface DesyncRecoveryResult {
  action: 'recreated' | 'marked_broken' | 'removed';
  details: string;
}

function recoverDesync(
  tracker: MultiAgentRepoTracker,
  streamId: string
): DesyncRecoveryResult {
  const stream = tracker.getStream(streamId);

  // Check if branch exists
  try {
    execSync(`git rev-parse stream/${streamId}`, { cwd: tracker.repoPath });
    // Branch exists but DB is wrong - sync from git
    return { action: 'recreated', details: 'Synced DB from git state' };
  } catch {
    // Branch doesn't exist
  }

  // Check if base commit exists
  try {
    execSync(`git rev-parse ${stream.baseCommit}`, { cwd: tracker.repoPath });
    // Can recreate branch from base
    execSync(
      `git branch stream/${streamId} ${stream.baseCommit}`,
      { cwd: tracker.repoPath }
    );
    return { action: 'recreated', details: 'Recreated branch from base commit' };
  } catch {
    // Base commit is gone too
  }

  // Mark as broken
  tracker.db.prepare(`
    UPDATE streams SET status = 'broken', metadata = json_set(metadata, '$.error', ?)
    WHERE id = ?
  `).run('Base commit not found, cannot recover', streamId);

  return {
    action: 'marked_broken',
    details: 'Base commit not found, stream marked as broken'
  };
}
```

### Partial Operation Recovery

```typescript
interface OperationCheckpoint {
  operationId: string;
  streamId: string;
  opType: string;
  step: number;
  totalSteps: number;
  beforeState: string;
  currentState: string;
  startedAt: number;
}

class OperationRecovery {
  private db: Database;

  /**
   * Check for incomplete operations on startup.
   */
  checkForIncomplete(): OperationCheckpoint[] {
    return this.db.prepare(`
      SELECT * FROM operation_checkpoints
      WHERE step < total_steps
      ORDER BY started_at DESC
    `).all();
  }

  /**
   * Record checkpoint during multi-step operation.
   */
  checkpoint(data: OperationCheckpoint): void {
    this.db.prepare(`
      INSERT OR REPLACE INTO operation_checkpoints
      (operation_id, stream_id, op_type, step, total_steps, before_state, current_state, started_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      data.operationId,
      data.streamId,
      data.opType,
      data.step,
      data.totalSteps,
      data.beforeState,
      data.currentState,
      data.startedAt
    );
  }

  /**
   * Clear checkpoint after successful completion.
   */
  complete(operationId: string): void {
    this.db.prepare('DELETE FROM operation_checkpoints WHERE operation_id = ?')
      .run(operationId);
  }

  /**
   * Recover from incomplete operation.
   */
  recover(checkpoint: OperationCheckpoint, worktree: string): void {
    // Roll back to before_state
    execSync(
      `git reset --hard ${checkpoint.beforeState}`,
      { cwd: worktree }
    );

    // Remove checkpoint
    this.complete(checkpoint.operationId);

    console.log(`Recovered operation ${checkpoint.operationId}: reset to ${checkpoint.beforeState}`);
  }
}
```

## Startup Recovery Flow

```typescript
async function startupRecovery(tracker: MultiAgentRepoTracker): Promise<void> {
  const recovery = new OperationRecovery(tracker.db);

  // Check for incomplete operations
  const incomplete = recovery.checkForIncomplete();

  for (const checkpoint of incomplete) {
    console.log(`Found incomplete operation: ${checkpoint.operationId}`);

    // Get worktree for this stream
    const worktree = tracker.getWorktreeForStream(checkpoint.streamId);

    if (worktree) {
      recovery.recover(checkpoint, worktree);
    } else {
      console.warn(`No worktree for stream ${checkpoint.streamId}, removing checkpoint`);
      recovery.complete(checkpoint.operationId);
    }
  }

  // Check for stale locks
  const staleLocks = tracker.db.prepare(`
    SELECT * FROM stream_locks WHERE acquired_at < ?
  `).all(Date.now() / 1000 - 300);  // 5 minutes

  for (const lock of staleLocks) {
    console.log(`Releasing stale lock on stream ${lock.stream_id} held by ${lock.agent_id}`);
    tracker.streamLock.release(lock.stream_id, lock.agent_id);
  }
}
```

## Health Check

```typescript
interface HealthCheckResult {
  healthy: boolean;
  issues: string[];
  streamCount: number;
  activeAgents: number;
  staleLocks: number;
  incompleteOps: number;
}

function healthCheck(tracker: MultiAgentRepoTracker): HealthCheckResult {
  const issues: string[] = [];

  // Count streams
  const streamCount = tracker.db.prepare('SELECT COUNT(*) as count FROM streams').get().count;

  // Count active agents
  const activeAgents = tracker.db.prepare(`
    SELECT COUNT(DISTINCT agent_id) as count FROM stream_guards
    WHERE last_write > ?
  `).get(Date.now() / 1000 - 60).count;

  // Check for stale locks
  const staleLocks = tracker.db.prepare(`
    SELECT COUNT(*) as count FROM stream_locks WHERE acquired_at < ?
  `).get(Date.now() / 1000 - 300).count;

  if (staleLocks > 0) {
    issues.push(`${staleLocks} stale locks detected`);
  }

  // Check for incomplete operations
  const incompleteOps = tracker.db.prepare(`
    SELECT COUNT(*) as count FROM operation_checkpoints WHERE step < total_steps
  `).get().count;

  if (incompleteOps > 0) {
    issues.push(`${incompleteOps} incomplete operations`);
  }

  return {
    healthy: issues.length === 0,
    issues,
    streamCount,
    activeAgents,
    staleLocks,
    incompleteOps
  };
}
```

# Safety and Garbage Collection (Phase 7)

Parent: [[s-9brh|Multi-Agent Git Tracking System]]

## Overview

Phase 7 adds safety mechanisms and cleanup pipelines:
- **Stream Guards**: Optimistic concurrency to detect concurrent modifications
- **Working Copy Snapshots**: Protect uncommitted work during risky operations
- **Operation Checkpoints**: Recovery from crashed mid-operation
- **Archive → Prune Pipeline**: Stream lifecycle cleanup with configurable GC

## Design Decisions

| Decision | Choice | Rationale |
|----------|--------|-----------|
| Guard model | Optimistic concurrency | No deadlock risk, works with existing locks |
| GC config storage | Database table | Persists across sessions |
| Auto-archive | Configurable, default on | Convenience with flexibility |
| Snapshot storage | Git stash | Simple, 90-day reflog expiry documented |
| Startup recovery | Auto by default, configurable | Safety without forcing it |

## Stream Guards (Optimistic Concurrency)

Guards track "who wrote last" to detect concurrent modifications without blocking.

```typescript
interface StreamGuard {
  streamId: string;
  agentId: string;
  lastWrite: number;  // timestamp
}

// Touch guard after successful write
function touchGuard(db: Database, streamId: string, agentId: string): void;

// Validate no one else wrote since our last read
function validateGuard(db: Database, streamId: string, agentId: string, sinceTimestamp: number): boolean;

// Clear guard (on stream delete/archive)
function clearGuard(db: Database, streamId: string): void;

// Get current guard state
function getGuard(db: Database, streamId: string): StreamGuard | null;
```

**Usage pattern:**
```typescript
const guard = getGuard(db, streamId);
const readTimestamp = Date.now();

// ... do work ...

if (guard && !validateGuard(db, streamId, agentId, readTimestamp)) {
  throw new ConcurrentModificationError(streamId);
}

// perform write
touchGuard(db, streamId, agentId);
```

## Working Copy Snapshots

Protect uncommitted work using git stash with tracking.

```typescript
interface Snapshot {
  id: string;
  worktree: string;
  agentId: string;
  reason: string;
  stashRef: string;
  headAtSnapshot: string;
  createdAt: number;
}

function snapshot(db: Database, worktree: string, agentId: string, reason: string): string | null;
function restore(db: Database, snapshotId: string, worktree: string): boolean;
function listSnapshots(db: Database, options?: { worktree?: string; agentId?: string }): Snapshot[];
function deleteSnapshot(db: Database, snapshotId: string): void;
function pruneSnapshots(db: Database, olderThanDays: number): number;
```

**Limitation:** Git stash refs expire with reflog (default 90 days). For longer retention, snapshots should be restored or committed.

