## Core Functions

### Worker Task Lifecycle (`src/worker-tasks.ts`)

```typescript
// Create a task under a stream
createTask(db, options: CreateTaskOptions): string

// Get task by ID
getTask(db, id: string): WorkerTask | null

// List tasks for a stream
listTasks(db, streamId: string, options?: {
  status?: WorkerTaskStatus;
  agentId?: string;
}): WorkerTask[]

// Start a task - assigns agent, creates ephemeral branch from stream HEAD
startTask(db, repoPath, options: StartTaskOptions): { 
  branchName: string; 
  startCommit: string 
}

// Complete a task - merges to stream with --no-ff merge commit
completeTask(db, repoPath, options: CompleteTaskOptions): { 
  mergeCommit: string 
}

// Abandon a task - marks abandoned, optionally deletes branch
abandonTask(db, repoPath, taskId: string): void

// Release task back to open (for recovery from stuck state)
releaseTask(db, taskId: string): void

// Cleanup old worker branches
cleanupWorkerBranches(db, repoPath, options?: {
  olderThanMs?: number;      // Default: 24h
  orphanedOnly?: boolean;
}): { deleted: string[]; errors: string[] }

// Recover tasks stuck in in_progress (startup recovery)
recoverStaleTasks(db, thresholdMs?: number): { released: string[] }
